begin Pids = [P || P <- erlang:processes(), case erlang:process_info(P, dictionary) of {dictionary, D} -> proplists:get_value('$initial_call', D) =:= {cowboy_stream_h, request_process, 3}; _ -> false end], CowboyConns = [P || P <- erlang:processes(), case erlang:process_info(P, current_function) of {current_function, {cowboy_http2, loop, _}} -> true; _ -> false end], {cowboy_stream_handlers, length(Pids), cowboy_connections, length(CowboyConns)} end.
